--
-- Table structure for table `ticketdetails`
--

DROP TABLE IF EXISTS `ticketdetails`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `ticketdetails` (
  `id` int NOT NULL AUTO_INCREMENT,
  `ticketcode` varchar(50) NOT NULL,
  `customername` varchar(45) NOT NULL,
  `controllerno` varchar(45) NOT NULL,
  `head` varchar(45) DEFAULT NULL,
  `imei` varchar(50) DEFAULT NULL,
  `hp` varchar(45) DEFAULT NULL,
  `motortype` varchar(45) DEFAULT NULL,
  `state` varchar(45) NOT NULL,
  `district` varchar(45) NOT NULL,
  `village` varchar(45) DEFAULT NULL,
  `block` varchar(45) DEFAULT NULL,
  `complainttype` varchar(100) NOT NULL,
  `faultcode` varchar(100) NOT NULL,
  `details` text,
  `picture` varchar(255) DEFAULT NULL,
  `status` varchar(45) DEFAULT NULL,
  `user_id` int NOT NULL,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`,`user_id`),
  UNIQUE KEY `ticketcode_UNIQUE` (`ticketcode`),
  KEY `user_id_idx` (`user_id`),
  CONSTRAINT `user_id` FOREIGN KEY (`user_id`) REFERENCES `userdetails` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=259 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

